import math

def compute_bpc(
    nll_per_token: list[float],  # negative log-likelihoods (natural log)
    token_lengths: list[int],    # number of characters in each token
) -> float:
    """Compute bits-per-character, independent of tokenizer granularity."""
    total_nll_bits = sum(nll * (1 / math.log(2)) for nll in nll_per_token)
    total_chars    = sum(token_lengths)
    return total_nll_bits / total_chars if total_chars else float('inf')
